import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out_lines = []
    idx = 1
    for _ in range(t):
        s = data[idx]
        idx += 1
        if s[0] == s[-1]:
            out_lines.append(s)
        else:
            # change the first character to match the last one
            new_s = s[-1] + s[1:]
            out_lines.append(new_s)
    sys.stdout.write("\n".join(out_lines))

