import sys

def solve() -> None:
    data = sys.stdin.read().split()
    it = iter(data)
    t = int(next(it))
    res = []
    for _ in range(t):
        x1 = int(next(it))
        p1 = int(next(it))
        x2 = int(next(it))
        p2 = int(next(it))

        d1 = len(str(x1))
        d2 = len(str(x2))

        total1 = d1 + p1
        total2 = d2 + p2

        if total1 > total2:
            res.append('>')
        elif total1 < total2:
            res.append('<')
        else:
            k = min(p1, p2)
            p1 -= k
            p2 -= k

            if p1 == 0 and p2 == 0:
                if x1 > x2:
                    res.append('>')
                elif x1 < x2:
                    res.append('<')
                else:
                    res.append('=')
            else:
                if p1 > 0:
                    val1 = x1 * (10 ** p1)
                    val2 = x2
                else:
                    val1 = x1
                    val2 = x2 * (10 ** p2)

                if val1 > val2:
                    res.append('>')
                elif val1 < val2:
                    res.append('<')
                else:
                    res.append('=')

    sys.stdout.write('\n'.join(res))

